void solve(int CASE)
{
	ll n, m, A, B; cin >> n >> m >> A >> B;
	var a = vector<string>(n + 1);
	var g = vector<vector<ll>>(1ll << m);
	fa(i, 1, n) {
		cin >> a[i];
		a[i] = ' ' + a[i];
		int st = 0;
		fa(j, 1, m)st += (a[i][j] - '0') * (1 << (j - 1));
		g[st].pb(i);
	}

	// 预处理行状态 s 对应的下标 i 的前缀和
	var pre = vector<vector<ll>>(1ll << m);
	fa(t, 0, (1ll << m) - 1) {
		if (g[t].size()) {
			pre[t].pb(g[t][0]);
			fa(i, 1, vs(g[t])) {
				ll now = pre[t][i - 1] + g[t][i];
				pre[t].pb(now);
			}
		}
	}

	// 设 y = sum{ a[i][j] }，x = sum{ a[i][j] * j }
	// 对于行状态 s，
	//		不翻转: ans1 = A * i * y + B * x
	//		翻转:   ans2 = A * i * (m - y) + B * (m * (m + 1) / 2 - x)
	// 是否翻转：ans2 >= ans1
	//		A * i * (m - 2 * y) + B * (m * (m + 1) / 2 - 2 * x) >= 0
	// 
	// 设 A1 = A * y，A2 = A * (m - y)
	// 设 B1 = B * x，B2 = B * (m * (m + 1) / 2 - x)

	// 枚举列翻转后，每一行可能的状态 t
	// 算出 H1、H2，满足翻转条件的最小 i
	var A1 = vector<ll>(1ll << m);
	var A2 = vector<ll>(1ll << m);
	var B1 = vector<ll>(1ll << m);
	var B2 = vector<ll>(1ll << m);
	var ti = vector<pii>(1ll << m);
	fa(t, 0, (1ll << m) - 1) { // 枚举行状态
		ll y = 0, x = 0;
		fa(j, 1, m)if (t & (1 << (j - 1))) {
			y += 1;
			x += j;
		}
		A1[t] = A * y;
		A2[t] = A * (m - y);
		B1[t] = B * x;
		B2[t] = B * (m * (m + 1) / 2 - x);
		if (m == 2 * y or A == 0) {
			if (B * (m * (m + 1) / 2 - 2 * x) < 0)ti[t] = { INF,0 };
			else ti[t] = { 0,0 };
		}
		else {
			if (A * (m - 2 * y) > 0) {
				ti[t] = { 
					(ll)ceil(db(B * (2 * x - m * (m + 1) / 2))
					/
					(A * (m - 2 * y)))
					, 0 };
			}
			else {
				ti[t] = {
					(B * (2 * x - m * (m + 1) / 2))
					/
					(A * (m - 2 * y))
					, 1 };
			}
		}
		//debug(t, A1[t], A2[t], B1[t], B2[t], ti[t]);
	}

	ll ans = -LNF;
	fa(t, 0, (1ll << m) - 1) {      // 枚举列是否翻转
		ll res = 0;
		fa(st, 0, (1ll << m) - 1)   // 枚举可能的行状态 st
			if (g[st].size()) {
				int s = st;         // 当前的实际行状态 s
				fa(j, 1, m)if (t & (1 << (j - 1)))s ^= (1 << (j - 1));

				if (ti[s].py == 0) {
					var it = lower_bound(all(g[st]), ti[s].px);
					if (it == g[st].end()) {
						res += pre[st].back() * A1[s];
						res += g[st].size() * B1[s];
					}
					else {
						int id = distance(g[st].begin(), it);
						if (id >= 1)
							res += pre[st][id - 1] * A1[s] + (pre[st].back() - pre[st][id - 1]) * A2[s];
						else 
							res += pre[st].back() * A2[s];
						res += id * B1[s] + (g[st].size() - id) * B2[s];
					}
				}
				else {
					var it = upper_bound(all(g[st]), ti[s].px);
					if (it == g[st].end()) {
						res += pre[st].back() * A2[s];
						res += g[st].size() * B2[s];
					}
					else {
						int id = distance(g[st].begin(), it);
						if (id >= 1)
							res += pre[st][id - 1] * A2[s] + (pre[st].back() - pre[st][id - 1]) * A1[s];
						else 
							res += pre[st].back() * A1[s];
						res += id * B2[s] + (g[st].size() - id) * B1[s];
					}
				}
			}
		ans = max(res, ans);
	}
	cout << ans << endl;
	return;
}
